using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=2e5+5;
int fa[MAXN],n,k,ans;
int find(int x)
{
	return ((fa[x]==x)?(x):(fa[x]=find(fa[x])));
}
signed main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n=read(),k=read(); 
	FOR(i,1,n*3)fa[i] = i;
	FOR(i,1,k)
	{
		int a=read(),b=read(),c=read();
		if(b>n||c>n||(a==2&&b==c))
		{
			++ans;
			continue;
		}
		if(a==2)
		{
			int temp=(find(b)==find(c)||find(b+n*2)==find(c)||find(c+n)==find(b));
			ans+=temp;
			if(!(temp))
			{
				fa[find(c+n)]=find(b+2*n);
				fa[find(b)]=find(c+2*n);
				fa[find(b+n)]=find(c);
			}
		}
		if(a==1)
		{
			int temp=((find(b+n)==find(c))||(find(b+2*n)==find(c)));
			ans+=temp;
			if(!(temp))
			{
				fa[find(b+2*n)]=find(c+2*n);
				fa[find(b+n)]=find(c+n);
				fa[find(b)]=find(c);
			}
		}
	}
	write(ans);
	return false;
}
